def gf_index(k, j):

    return k * o + j


def sat_var(k, j, bit):

    return _sage_const_4  * gf_index(k, j) + bit + _sage_const_1 


def multiplication_matrix(c):

    matrix = [
        [_sage_const_0  for _ in range(_sage_const_4 )]
        for _ in range(_sage_const_4 )
    ]

    for input_bit in range(_sage_const_4 ):

        basis_element = _sage_const_1  << input_bit

        product = gf16_mul_int(
            c,
            basis_element
        )

        for output_bit in range(_sage_const_4 ):

            matrix[output_bit][input_bit] = (
                (product >> output_bit) & _sage_const_1 
            )

    return matrix


MUL_MATRIX = {

    c: multiplication_matrix(c)

    for c in range(_sage_const_16 )
}



# Variable term:
#
# F(number) * x_k_j

VARIABLE_TERM_RE = re.compile(
    r'^F\(\s*(\d+)\s*\)\s*\*\s*x_(\d+)_(\d+)$'
)


# Constant:
#
# F(number)

CONSTANT_TERM_RE = re.compile(
    r'^F\(\s*(\d+)\s*\)$'
)
BARE_CONSTANT_RE = re.compile(
    r'^(\d+)$'
)

def parse_side(side):

    """
    Parse one side of an equation.

    Returns:

        variable_terms:
            dictionary

                (k,j) -> GF(16) nibble coefficient

        constant:
            GF(16) nibble
    """

    variable_terms = {}

    constant = _sage_const_0 


    # Normalize whitespace

    side = side.strip()


    if side == "":
        return variable_terms, constant


    # Equations generated by the C code use '+' between terms.
    #
    # In characteristic 2:
    #
    #       subtraction = addition
    #
    # but the input is expected to contain '+'.

    terms = side.split("+")


    for raw_term in terms:

        term = raw_term.strip()

        if not term:
            continue


        # -----------------------------------------------
        # Variable term:
        #
        # F(c)*x_k_j
        # -----------------------------------------------

        match = VARIABLE_TERM_RE.match(term)

        if match:

            coeff = int(match.group(_sage_const_1 )) & _sage_const_0xF 
            k = int(match.group(_sage_const_2 ))
            j = int(match.group(_sage_const_3 ))


            if not (_sage_const_0  <= k < v):

                raise ValueError(
                    "Invalid oil row index: %d" % k
                )


            if not (_sage_const_0  <= j < o):

                raise ValueError(
                    "Invalid oil column index: %d" % j
                )


            key = (k, j)


            # If the same variable appears multiple times:
            #
            #     c1*x + c2*x
            #
            # combine coefficients using GF(16) addition,
            # which is XOR.

            old = variable_terms.get(
                key,
                _sage_const_0 
            )

            new = gf16_add_int(
                old,
                coeff
            )


            if new == _sage_const_0 :

                variable_terms.pop(
                    key,
                    None
                )

            else:

                variable_terms[key] = new


            continue


        # -----------------------------------------------
        # Constant:
        #
        # F(c)
        # -----------------------------------------------

        match = CONSTANT_TERM_RE.match(term)

        if match:

            value = int(
                match.group(_sage_const_1 )
            ) & _sage_const_0xF 

            constant = gf16_add_int(
                constant,
                value
            )

            continue

        match = BARE_CONSTANT_RE.match(term)

        if match:

            value = int(
                match.group(_sage_const_1 )
            ) & _sage_const_0xF 

            constant = gf16_add_int(
                constant,
                value
            )

            continue

        raise ValueError(
            "Could not parse term:\n%s"
            % term
        )


    return variable_terms, constant


# ============================================================
# 7. Parse a complete equation
#
#       lhs == rhs
#
# Move everything to the left:
#
#       lhs + rhs = 0
#
# because characteristic = 2.
# ============================================================

def parse_equation(line):

    if "==" not in line:

        raise ValueError(
            "Equation does not contain ==:\n%s"
            % line
        )


    lhs_text, rhs_text = line.split(
        "==",
        _sage_const_1 
    )


    lhs_vars, lhs_const = parse_side(
        lhs_text
    )

    rhs_vars, rhs_const = parse_side(
        rhs_text
    )


    # Combine both sides:
    #
    # lhs - rhs = 0
    #
    # Over characteristic 2:
    #
    # lhs + rhs = 0

    variables = dict(lhs_vars)


    for key, coeff in rhs_vars.items():

        old = variables.get(
            key,
            _sage_const_0 
        )

        new = gf16_add_int(
            old,
            coeff
        )

        if new == _sage_const_0 :

            variables.pop(
                key,
                None
            )

        else:

            variables[key] = new


    constant = gf16_add_int(
        lhs_const,
        rhs_const
    )


    # Equation is now:
    #
    #       sum(coeff*x) + constant = 0
    #
    # therefore:
    #
    #       sum(coeff*x) = constant
    #
    # since -constant = constant in characteristic 2.

    rhs = constant


    return variables, rhs


