# 9. Convert each GF(16) equation into four XOR equations
#
# For:
#
#       sum_j c_j*x_j = rhs
#
# generate:
#
#       bit equation 0
#       bit equation 1
#       bit equation 2
#       bit equation 3
#
# over GF(2).
# ============================================================

xor_equations = []


for eq_index, (variables, rhs) in enumerate(
    parsed_equations
):

    xor_sets = [

        set(),
        set(),
        set(),
        set()

    ]


    for (k, j), coeff in variables.items():

        matrix = MUL_MATRIX[coeff]


        for output_bit in range(_sage_const_4 ):

            for input_bit in range(_sage_const_4 ):

                if matrix[output_bit][input_bit]:

                    variable = sat_var(
                        k,
                        j,
                        input_bit
                    )


                    # XOR insertion:
                    #
                    # x XOR x = 0

                    if variable in xor_sets[output_bit]:

                        xor_sets[output_bit].remove(
                            variable
                        )

                    else:

                        xor_sets[output_bit].add(
                            variable
                        )


    # RHS nibble -> four RHS bits

    for output_bit in range(_sage_const_4 ):

        rhs_bit = (
            rhs >> output_bit
        ) & _sage_const_1 


        xor_equations.append(
            (
                sorted(
                    xor_sets[output_bit]
                ),
                rhs_bit
            )
        )


